parameters.jsCode:
// PARSER JULIA OUTPUT + SSE
// Extrai SSE, parseia tags multiline, entende #AGENDA como JSON,
// preserva memória anterior e devolve estrutura organizada.

function safeString(v) {
  return v === undefined || v === null ? '' : String(v);
}

function isPlaceholder(value) {
  return /\{\{.*\}\}/.test(safeString(value).trim());
}

function keepOldIfEmpty(newValue, oldValue) {
  const n = safeString(newValue).trim();
  const o = safeString(oldValue).trim();
  if (n === '' || isPlaceholder(n)) return o;
  return n;
}

function normalizeEmail(email) {
  return safeString(email).trim().toLowerCase();
}

function safeJsonParse(value, fallback = null) {
  try {
    return JSON.parse(value);
  } catch {
    return fallback;
  }
}

function parseTaggedOutput(text) {
  const source = safeString(text).replace(/\r/g, '');
  const lines = source.split('\n');

  const tags = {};
  const messageLines = [];

  let currentTag = null;
  let currentValue = [];

  const flushCurrentTag = () => {
    if (currentTag) {
      tags[currentTag] = currentValue.join('\n').trim();
      currentTag = null;
      currentValue = [];
    }
  };

  for (const line of lines) {
    const match = line.match(/^#([A-Z0-9_]+):(.*)$/);

    if (match) {
      flushCurrentTag();
      currentTag = match[1];
      currentValue = [safeString(match[2]).trim()];
      continue;
    }

    if (currentTag) {
      currentValue.push(line);
    } else {
      messageLines.push(line);
    }
  }

  flushCurrentTag();

  return {
    tags,
    cleanMessage: Array.isArray(messageLines)
      ? messageLines.join('\n').split('#')[0].replace(/\n{3,}/g, '\n\n').trim()
      : String(messageLines || '').split('#')[0].replace(/\n{3,}/g, '\n\n').trim(),  };
}

function parseSSE(raw) {
  const text = safeString(raw);

  const lines = text
    .split('\n')
    .map(line => line.trim())
    .filter(line => line.startsWith('data: '));

  const events = [];

  for (const line of lines) {
    const jsonStr = line.replace(/^data:\s*/, '').trim();
    if (!jsonStr.startsWith('{')) continue;

    try {
      events.push(JSON.parse(jsonStr));
    } catch {
      // ignora chunk quebrado
    }
  }

  const workflowFinished = [...events].reverse().find(e => e.event === 'workflow_finished');
  const llmNodeFinished = [...events].reverse().find(
    e => e.event === 'node_finished' && e.data && e.data.node_id === 'llm'
  );
  const anyNodeFinishedWithText = [...events].reverse().find(
    e =>
      e.event === 'node_finished' &&
      e.data &&
      e.data.outputs &&
      (typeof e.data.outputs.text === 'string' || typeof e.data.outputs.answer === 'string')
  );

  const messageChunks = events
    .filter(e => e.event === 'message' && typeof e.answer === 'string')
    .map(e => e.answer);

  const finalAnswer =
    workflowFinished?.data?.outputs?.answer ||
    llmNodeFinished?.data?.outputs?.text ||
    anyNodeFinishedWithText?.data?.outputs?.text ||
    anyNodeFinishedWithText?.data?.outputs?.answer ||
    messageChunks.join('').trim() ||
    '';

  const conversationId =
    workflowFinished?.conversation_id ||
    llmNodeFinished?.conversation_id ||
    anyNodeFinishedWithText?.conversation_id ||
    events.find(e => e.conversation_id)?.conversation_id ||
    '';

  const messageId =
    workflowFinished?.message_id ||
    llmNodeFinished?.message_id ||
    anyNodeFinishedWithText?.message_id ||
    events.find(e => e.message_id)?.message_id ||
    '';

  return {
    finalAnswer,
    conversationId,
    messageId,
    rawEventsCount: events.length,
  };
}

function hasMeaningfulContent(text) {
  const t = safeString(text).trim();
  if (!t) return false;

  const parsed = parseTaggedOutput(t);
  const cleaned = safeString(parsed.cleanMessage).replace(/\s+/g, ' ').trim();
  return cleaned.length > 0;
}

function objectHasAnyValue(obj) {
  if (!obj || typeof obj !== 'object') return false;

  for (const value of Object.values(obj)) {
    if (typeof value === 'string' && value.trim() !== '') return true;
    if (typeof value === 'number' && !Number.isNaN(value)) return true;
    if (typeof value === 'boolean') return true;
    if (value && typeof value === 'object' && objectHasAnyValue(value)) return true;
  }

  return false;
}

function normalizeLeadSummary(value) {
  if (!value) return {};
  if (typeof value === 'object' && !Array.isArray(value)) return value;

  const parsed = safeJsonParse(safeString(value), {});
  return parsed && typeof parsed === 'object' && !Array.isArray(parsed) ? parsed : {};
}

function normalizeAgenda(value) {
  const base = {
    selected_option: '',
    selected_option_start: '',
    option_1_start: '',
    option_2_start: '',
    requested_day: '',
    requested_date: '',
    requested_period: '',
    requested_time_min: '',
    requested_time_max: '',
    email: '',
  };

  if (!value) return { ...base };

  let parsed = value;

  if (typeof value === 'string') {
    parsed = safeJsonParse(value, null);
  }

  if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) {
    return { ...base };
  }

  return {
    selected_option: safeString(parsed.selected_option).trim(),
    selected_option_start: safeString(parsed.selected_option_start).trim(),
    option_1_start: safeString(parsed.option_1_start).trim(),
    option_2_start: safeString(parsed.option_2_start).trim(),
    requested_day: safeString(parsed.requested_day).trim(),
    requested_date: safeString(parsed.requested_date).trim(),
    requested_period: safeString(parsed.requested_period).trim(),
    requested_time_min: safeString(parsed.requested_time_min).trim(),
    requested_time_max: safeString(parsed.requested_time_max).trim(),
    email: normalizeEmail(parsed.email),
  };
}

function isWeakLeadSummary(summaryObj) {
  if (!summaryObj || typeof summaryObj !== 'object') return true;
  return !objectHasAnyValue(summaryObj);
}

function hasStructuredOutput(parsedObj) {
  return [
    parsedObj.lead_status,
    parsedObj.last_intent,
    parsedObj.lead_summary,
    parsedObj.system_event,
    parsedObj.agenda?.selected_option,
    parsedObj.agenda?.selected_option_start,
    parsedObj.agenda?.option_1_start,
    parsedObj.agenda?.option_2_start,
    parsedObj.agenda?.requested_day,
    parsedObj.agenda?.requested_date,
    parsedObj.agenda?.requested_period,
    parsedObj.agenda?.requested_time_min,
    parsedObj.agenda?.requested_time_max,
    parsedObj.agenda?.email,
  ].some(v => safeString(v).trim() !== '');
}

function omitEmptyFields(obj) {
  if (!obj || typeof obj !== 'object' || Array.isArray(obj)) return obj;

  const cleaned = {};

  for (const [key, value] of Object.entries(obj)) {
    if (value === undefined || value === null) continue;

    if (typeof value === 'string') {
      if (value.trim() === '') continue;
      cleaned[key] = value;
      continue;
    }

    if (typeof value === 'number') {
      if (Number.isNaN(value)) continue;
      cleaned[key] = value;
      continue;
    }

    if (typeof value === 'boolean') {
      cleaned[key] = value;
      continue;
    }

    if (Array.isArray(value)) {
      if (value.length > 0) cleaned[key] = value;
      continue;
    }

    if (typeof value === 'object') {
      const nested = omitEmptyFields(value);
      if (nested && Object.keys(nested).length > 0) {
        cleaned[key] = nested;
      }
    }
  }

  return cleaned;
}

const input = $json;
const previousInputs = input.inputs || {};

// 1. tenta ler direto
let rawOutput =
  input.answer ||
  input.output ||
  input.text ||
  input.message ||
  input.response ||
  '';

// 2. se não veio direto, tenta extrair do SSE bruto
let conversationId = input.conversation_id || input.chatwoot?.dify_uuid || '';
let messageId = input.message_id || input.message?.message_id || '';
let rawEventsCount = input.raw_events_count || input.message?.raw_events_count || 0;

if ((!rawOutput || typeof rawOutput !== 'string') && input.data) {
  const sse = parseSSE(input.data);
  rawOutput = sse.finalAnswer || '';
  conversationId = conversationId || sse.conversationId;
  messageId = messageId || sse.messageId;
  rawEventsCount = rawEventsCount || sse.rawEventsCount;
}

// 3. memória anterior
const old = {
  lead_status: previousInputs.lead_status || input.last_known_status || '',
  last_intent: previousInputs.last_intent || '',
  lead_summary: normalizeLeadSummary(previousInputs.lead_summary || input.last_known_summary || {}),
  agenda: normalizeAgenda(previousInputs.agenda || {
    selected_option: previousInputs.selected_option || input.last_known_selected_option || '',
    selected_option_start: previousInputs.selected_option_start || input.last_known_selected_option_start || '',
    option_1_start: previousInputs.option_1_start || input.last_known_option_1_start || '',
    option_2_start: previousInputs.option_2_start || input.last_known_option_2_start || '',
    requested_day: previousInputs.requested_day || '',
    requested_date: previousInputs.requested_date || '',
    requested_period: previousInputs.requested_period || '',
    requested_time_min: previousInputs.requested_time_min || '',
    requested_time_max: previousInputs.requested_time_max || '',
    email: previousInputs.email || input.last_known_email || '',
  }),
  system_event: previousInputs.system_event || previousInputs.memory_system_event || input.last_system_event || input.chatwoot?.system_event || '',
};

// 4. parse do output da Julia
const parsedOutput = parseTaggedOutput(rawOutput);
const tags = parsedOutput.tags;

// prioridade: se vier #AGENDA em JSON, usa ela.
// se não vier, tenta fallback pelas tags separadas.
const agendaFromJsonTag = normalizeAgenda(tags.AGENDA);

const agendaFromFlatTags = normalizeAgenda({
  selected_option: tags.SELECTED_OPTION,
  selected_option_start: tags.SELECTED_OPTION_START,
  option_1_start: tags.OPTION_1_START,
  option_2_start: tags.OPTION_2_START,
  requested_day: tags.REQUESTED_DAY,
  requested_date: tags.REQUESTED_DATE,
  requested_period: tags.REQUESTED_PERIOD,
  requested_time_min: tags.REQUESTED_TIME_MIN,
  requested_time_max: tags.REQUESTED_TIME_MAX,
  email: tags.EMAIL,
});

const parsedAgenda = objectHasAnyValue(agendaFromJsonTag) ? agendaFromJsonTag : agendaFromFlatTags;

const parsed = {
  lead_status: safeString(tags.STATUS).trim(),
  last_intent: safeString(tags.LAST_INTENT).trim(),
  lead_summary: safeString(tags.LEAD_SUMMARY).trim(),
  agenda: parsedAgenda,
  system_event: safeString(tags.SYSTEM_EVENT).trim(),
  utms: safeString(tags.UTMS).trim(),
  error_flag: safeString(tags.ERROR_FLAG).trim(),
  error_message: safeString(tags.ERROR_MESSAGE).trim(),
};

// 5. consolida com memória anterior
const finalLeadStatus = keepOldIfEmpty(parsed.lead_status, old.lead_status) || 'QUALIFICANDO';
const finalLastIntent = keepOldIfEmpty(parsed.last_intent, old.last_intent);

const parsedLeadSummaryObj = normalizeLeadSummary(parsed.lead_summary);
const finalLeadSummary = objectHasAnyValue(parsedLeadSummaryObj)
  ? parsedLeadSummaryObj
  : old.lead_summary;

const finalAgendaRaw = {
  selected_option: keepOldIfEmpty(parsed.agenda.selected_option, old.agenda.selected_option),
  selected_option_start: keepOldIfEmpty(parsed.agenda.selected_option_start, old.agenda.selected_option_start),
  option_1_start: keepOldIfEmpty(parsed.agenda.option_1_start, old.agenda.option_1_start),
  option_2_start: keepOldIfEmpty(parsed.agenda.option_2_start, old.agenda.option_2_start),
  requested_day: keepOldIfEmpty(parsed.agenda.requested_day, old.agenda.requested_day),
  requested_date: keepOldIfEmpty(parsed.agenda.requested_date, old.agenda.requested_date),
  requested_period: keepOldIfEmpty(parsed.agenda.requested_period, old.agenda.requested_period),
  requested_time_min: keepOldIfEmpty(parsed.agenda.requested_time_min, old.agenda.requested_time_min),
  requested_time_max: keepOldIfEmpty(parsed.agenda.requested_time_max, old.agenda.requested_time_max),
  email: keepOldIfEmpty(parsed.agenda.email, old.agenda.email),
};

const finalAgenda = omitEmptyFields(finalAgendaRaw);
const finalSystemEvent = keepOldIfEmpty(parsed.system_event, old.system_event);

// 6. validação
const meaningfulContent = hasMeaningfulContent(rawOutput);
const hasStructuredTags = hasStructuredOutput(parsed);
const weakSummary = isWeakLeadSummary(finalLeadSummary);

const aiResponseInvalid =
  !meaningfulContent ||
  (!hasStructuredTags && !parsed.error_flag && !parsed.error_message) ||
  weakSummary;

// 7. resultado final
const result = {
  message: omitEmptyFields({
    raw_output: rawOutput,
    answer: parsedOutput.cleanMessage,
  }),

  chatwoot: omitEmptyFields({
    dify_uuid: conversationId,
    system_event: finalSystemEvent,
  }),

  inputs: omitEmptyFields({
    lead_status: finalLeadStatus,
    last_intent: finalLastIntent,
    lead_summary: finalLeadSummary,
    agenda: finalAgenda,
    error_flag:
      parsed.error_flag !== ''
        ? Number(parsed.error_flag)
        : aiResponseInvalid ? 1 : 0,
    error_message:
      parsed.error_message !== ''
        ? parsed.error_message
        : aiResponseInvalid
          ? 'EMPTY_OR_INVALID_AI_RESPONSE'
          : safeString(input.error_message || ''),
    retry_count: Number(input.retry_count || 0),
  }),
};

return [{ json: result }];

